def compute_score() -> tuple[str, float]:
    """Check that the (only) image on slide 6 is rotated ~45 degrees clockwise."""
    from pptx import Presentation

    SLIDE_IDX = 5  # slide numbers are 1-based
    TARGET_ROTATION = 45
    ROTATION_TOLERANCE = 2  # degrees

    # Load modified presentation
    prs = Presentation(modified_ppt_path)
    if len(prs.slides) <= SLIDE_IDX:
        return ("Slide 6 does not exist in modified presentation.", 0.0)
    slide = prs.slides[SLIDE_IDX]

    # Collect debug info about shapes
    shapes_debug = []
    picture_like_indices = []
    pics = []
    for idx, sh in enumerate(slide.shapes):
        stype = getattr(sh, "shape_type", None)
        name = getattr(sh, "name", "<no-name>")
        fill_type = None
        try:
            fill = getattr(sh, "fill", None)
            if fill is not None:
                fill_type = getattr(fill, "type", None)
        except Exception:
            pass
        has_image_attr = hasattr(sh, "image")
        # Primary detection: native picture shape_type == 13
        if stype == 13:
            pics.append(sh)
            picture_like_indices.append(idx)
        # Secondary detection: non-picture shape that has a picture fill
        elif has_image_attr or (fill_type is not None and str(fill_type).upper().endswith("PICTURE")):
            pics.append(sh)
            picture_like_indices.append(idx)
        shapes_debug.append({
            "idx": idx,
            "name": name,
            "shape_type": stype,
            "has_image_attr": has_image_attr,
            "fill_type": str(fill_type) if fill_type is not None else None,
        })

    if not pics:
        debug_msg = (
            f"No image found on slide 6. Total shapes={len(slide.shapes)}. "
            f"Shape summaries: "
            + "; ".join(
                f"#{d['idx']} type={d['shape_type']} name='{d['name']}' has_image={d['has_image_attr']} fill_type={d['fill_type']}"  # noqa: E501
                for d in shapes_debug
            )
        )
        return (debug_msg, 0.0)

    # If multiple, pick first but include note
    pic = pics[0]
    if len(pics) > 1:
        multi_note = f" (Multiple picture-like shapes detected indices={picture_like_indices}; using first index {picture_like_indices[0]})"
    else:
        multi_note = ""

    rotation = getattr(pic, "rotation", 0) % 360
    diff = min(abs(rotation - TARGET_ROTATION), abs(rotation + 360 - TARGET_ROTATION))

    if diff <= ROTATION_TOLERANCE:
        return (f"Image rotation {rotation}° within tolerance.{multi_note}", 1.0)
    return (f"Image rotation {rotation}°; expected {TARGET_ROTATION}° ±{ROTATION_TOLERANCE}°." + multi_note, 0.0)

def compute_score() -> tuple[str, float]:
    # Use ppt_diff for all types
    changed = False
    details = []
    # Slides
    for slide in ppt_diff.added_slides:
        if slide.slide_number != 6:
            changed = True
            details.append(f"Slide {slide.slide_number} added.")
    for slide in ppt_diff.removed_slides:
        if slide.slide_number != 6:
            changed = True
            details.append(f"Slide {slide.slide_number} removed.")
    for before, after in ppt_diff.modified_slides:
        if before.slide_number != 6 and after.slide_number != 6:
            changed = True
            details.append(f"Slide {before.slide_number} modified.")
    # Animations
    for ae in ppt_diff.added_animations + ppt_diff.removed_animations:
        if int(ae.slide_id) != 6:
            changed = True
            details.append(f"Animation on slide {ae.slide_id} changed.")
    for before, after in ppt_diff.modified_animations:
        if int(before.slide_id) != 6 and int(after.slide_id) != 6:
            changed = True
            details.append(f"Animation on slide {before.slide_id} modified.")
    # Transitions
    for tr in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if int(tr.slide_id) != 6:
            changed = True
            details.append(f"Transition on slide {tr.slide_id} changed.")
    for before, after in ppt_diff.modified_transitions:
        if int(before.slide_id) != 6 and int(after.slide_id) != 6:
            changed = True
            details.append(f"Transition on slide {before.slide_id} modified.")
    if changed:
        return ("Unintended changes detected on slides other than slide 6: " + "; ".join(details), 0.0)
    return ("No changes detected on slides other than slide 6.", 1.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    SLIDE_IDX = 5
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    if len(orig_prs.slides) <= SLIDE_IDX or len(mod_prs.slides) <= SLIDE_IDX:
        return ("Slide 6 missing in one of the presentations.", 0.0)
    orig_slide = orig_prs.slides[SLIDE_IDX]
    mod_slide = mod_prs.slides[SLIDE_IDX]
    orig_pics = [sh for sh in orig_slide.shapes if sh.shape_type == 13]
    mod_pics = [sh for sh in mod_slide.shapes if sh.shape_type == 13]
    import hashlib
    def get_pic_hash(pic):
        if hasattr(pic, 'image'):
            return hashlib.sha256(pic.image.blob).hexdigest()
        return None
    orig_hashes = set(get_pic_hash(pic) for pic in orig_pics)
    mod_hashes = set(get_pic_hash(pic) for pic in mod_pics)
    # Any extra in modified?
    added = mod_hashes - orig_hashes
    if added:
        return (f"{len(added)} new image(s) added to slide 6.", 0.0)
    return ("No new images added to slide 6.", 1.0)
